import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormGroup,
  RequiredValidator,
  Validators,
} from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { LoansService } from "src/app/core/services/loans.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { GetLoanDoubtfulInformationByLoanKey } from "src/app/views/Models/Loan/GetLoanDoubtfulInformationByLoanKey";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import * as customValidators from "src/app/core/validators/custom-validators";
import { InsertLoanDoubtful } from "src/app/views/Models/Loan/InsertLoanDoubtful";
import { GetInstallmentsByLoanKey } from "src/app/views/Models/Installments/GetInstallmentsByLoanKey";
import { InstallmentsService } from "src/app/core/services/installments.service";
import { LoanRejection } from "src/app/views/Models/Loan/LoanRejection";
import { UserInfo } from "src/app/core/models/UserInfo";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { InsertLoanWriteOff } from "src/app/views/Models/Loan/InsertLoanWriteOff";

interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface LoanSection {
  formGroup: FormGroup;
  visible: boolean;
  checkIfInputsValid: boolean;
}
interface DatabaseResponses {
  writeoffInformation: GetLoanDoubtfulInformationByLoanKey;
  getInstallmentsByLoanKey: GetInstallmentsByLoanKey[];
  loanCanRes: LoanRejection[];
}
@Component({
  selector: "app-loan-write",
  templateUrl: "./loan-write.page.html",
  styleUrls: ["./loan-write.page.css"],
})
export class LoanWritePage implements OnInit {
  writeoff_cause: LoanRejection[];
  constructor(
    private alertService: AlertService,
    private formBuilder: FormBuilder,
    private loanService: LoansService,
    private installmentService: InstallmentsService,
    private authService: MohassilAuthService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  clientSearchCardSection: ClientSearchSection;
  loanSection: LoanSection;
  databaseResponses: DatabaseResponses;
  userInfo: UserInfo;
  //#endregion

  get writeoffInformation(): GetLoanDoubtfulInformationByLoanKey {
    return this.databaseResponses.writeoffInformation;
  }
  get getInstallmentsByLoanKey(): GetInstallmentsByLoanKey[] {
    return this.databaseResponses.getInstallmentsByLoanKey;
  }
  async ngOnInit() {
    this.initializeForms();
    this.userInfo = await this.authService.getUserInfo();
  }
  initializeForms() {
    this.clientSearchCardSection = {
      visible: true,
      clientInformation: null,
    };
    this.loanSection = {
      checkIfInputsValid: false,
      visible: false,
      formGroup: this.formBuilder.group({
        transactionDate: [
          null,
          customValidators.dateTypeStringValidator({ required: true }),
        ],
        writeoff_cause: [null, Validators.required],
        loanNotes: [],
      }),
    };
    this.databaseResponses = {
      writeoffInformation: null,
      getInstallmentsByLoanKey: [],
      loanCanRes: [],
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      this.databaseResponses.loanCanRes = await this.loanService
        .GetLoanCancelRef(Number(this.userInfo.org_code))
        .toPromise();
      this.writeoff_cause = this.databaseResponses.loanCanRes;
      this.clientSearchCardSection.clientInformation = searchResult;
      this.databaseResponses.writeoffInformation = await this.loanService
        .getLoanWriteOffInformationByLoanKey(Number(searchResult.loan_key))
        .toPromise();
      this.loanSection.formGroup.patchValue({
        loanNotes: this.databaseResponses.writeoffInformation.loanNotes,
      });
      this.databaseResponses.getInstallmentsByLoanKey =
        await this.installmentService
          .getInstallmentsByLoanKey(Number(searchResult.loan_key))
          .toPromise();
      this.clientSearchCardSection.visible = false;
      this.loanSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
  backButton() {
    if (this.loanSection.visible) {
      this.loanSection.checkIfInputsValid = false;
      this.loanSection.visible = false;
      this.loanSection.formGroup.reset();
      this.clientSearchCardSection = {
        clientInformation: null,
        visible: true,
      };
    }
  }
  async insertwriteoffLoan() {
    try {
      this.loanSection.checkIfInputsValid = true;
      if (!this.loanSection.formGroup.valid) return;
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      const { value } = this.loanSection.formGroup;
      const request: InsertLoanWriteOff = {
        loanKey: this.writeoffInformation.loanKey,
        loanUuc: this.writeoffInformation.loanUuc,
        transactionDate: value.transactionDate,
        wrt_off_reason: value.writeoff_cause,
        loanNotes: value.loanNotes,
      };
      await this.loanService.insertLoanWriteoff(request).toPromise();
      await this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
}
